patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index fdadf729fbd5..8a4a4458c155 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8068,6 +8068,36 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   }
   }

+  // fcmp pred (select cond, X, -X), 0 -> fcmp pred X, 0
+  // fcmp pred (select cond, -X, X), 0 -> fcmp pred X, 0
+  // This is valid for predicates where sign of zero doesn't matter,
+  // because fcmp pred X, 0 == fcmp pred -X, 0 for these predicates.
+  {
+    Value *X = nullptr;
+    if (match(Op1, m_AnyZeroFP())) {
+      if (match(Op0, m_Select(m_Value(), m_Value(X), m_FNeg(m_Deferred(X))))) {
+        // matched: select cond, X, -X
+      } else if (match(Op0, m_Select(m_Value(), m_FNeg(m_Value(X)), m_Deferred(X)))) {
+        // matched: select cond, -X, X
+      } else {
+        X = nullptr;
+      }
+    }
+    if (X) {
+      switch (Pred) {
+      case FCmpInst::FCMP_OEQ:
+      case FCmpInst::FCMP_UEQ:
+      case FCmpInst::FCMP_ONE:
+      case FCmpInst::FCMP_UNE:
+      case FCmpInst::FCMP_ORD:
+      case FCmpInst::FCMP_UNO:
+        return new FCmpInst(Pred, X, ConstantFP::getZero(OpType), "", &I);
+      default:
+        break;
+      }
+    }
+  }
+
   if (Instruction *R = foldFabsWithFcmpZero(I, *this))
     return R;

